class Solution:
    def kWeakestRows(self, mat, k):
        def count_soldiers(row):
            lo, hi = 0, len(row)
            while lo < hi:
                mid = (lo + hi) // 2
                if row[mid] == 1:
                    lo = mid + 1
                else:
                    hi = mid
            return lo

        order = sorted(range(len(mat)), key=lambda i: (count_soldiers(mat[i]), i))
        return order[:k]

