var kWeakestRows = function(mat, k) {
    const idx = mat.map((row, i) => [row.reduce((a, b) => a + b, 0), i]);
    idx.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
    return idx.slice(0, k).map(p => p[1]);
};
